      <p
        className="mono"
        style={{
          color: "var(--amber-dim)",
          fontSize: "0.6rem",
          letterSpacing: "0.22em",
          margin: "0.4rem 0 1.4rem",
          textTransform: "uppercase",
        }}
      >
        Reader response · firm reply
      </p>
      <ol style={{ display: "grid", gap: "1.4rem", listStyle: "none", margin: 0, padding: 0 }}>
        {entries.map((entry) => (
          <li
            key={entry.responseId}
            style={{
              borderLeft: "2px solid var(--amber-dim)",
              paddingLeft: "1rem",
            }}
          >
            <p
              className="mono"
              style={{
                color: "var(--amber-dim)",
                fontSize: "0.6rem",
                letterSpacing: "0.18em",
                margin: 0,
                textTransform: "uppercase",
              }}
            >
              {entry.responderLabel} · {entry.repliedAt.toISOString().slice(0, 10)}
            </p>
            <p
              style={{
                color: "var(--parchment)",
                fontFamily: "'EB Garamond', serif",
                fontStyle: "italic",
                lineHeight: 1.55,
                margin: "0.4rem 0 0.7rem",
                whiteSpace: "pre-wrap",
              }}
            >
              {entry.responseBody}
            </p>
            {entry.responseCitationUrl ? (
              <p style={{ margin: "0 0 0.6rem" }}>
                <a
                  className="mono"
                  href={entry.responseCitationUrl}
                  rel="noreferrer"
                  target="_blank"
                  style={{
                    color: "var(--amber-dim)",
                    fontSize: "0.65rem",
                    textDecoration: "none",
                  }}
                >
                  {entry.responseCitationUrl}
                </a>
              </p>
            ) : null}
            <p
              className="mono"
              style={{
                color: "var(--amber-dim)",
                fontSize: "0.6rem",
                letterSpacing: "0.18em",
                margin: "0.4rem 0 0.2rem",
                textTransform: "uppercase",
              }}
            >
              Theseus
            </p>
            <p
              style={{
                color: "var(--parchment)",
                fontFamily: "'EB Garamond', serif",
                lineHeight: 1.55,
                margin: 0,
                whiteSpace: "pre-wrap",
              }}
            >
              {entry.replyBody}
            </p>
          </li>
        ))}
      </ol>
    </section>
  );
}

